script:
frappe.ui.form.on('Sales Invoice', {
    custom_tevkifat_kodu: function(frm) {
        if (!frm.doc.custom_tevkifat_kodu) {
            frm.set_value('custom_tevkifat_tutarı', 0);
            temizle_tevkifat_satiri(frm);
            return;
        }

        frappe.db.get_doc('Tevkifat Kodlari', frm.doc.custom_tevkifat_kodu)
            .then(doc => {
                let tevkifat_orani = parseFloat(doc.oran) || 0;
                let toplam_kdv = 0;

                // Faturadaki "Pozitif" KDV'leri topluyoruz
                if (frm.doc.taxes && frm.doc.taxes.length > 0) {
                    frm.doc.taxes.forEach(tax => {
                        if (tax.tax_amount > 0 && !(tax.description && tax.description.includes("Tevkifat"))) {
                            toplam_kdv += (tax.base_tax_amount || 0);
                        }
                    });
                }

                let kesinti = toplam_kdv * (tevkifat_orani / 100);
                frm.set_value('custom_tevkifat_tutarı', kesinti);
                
                // Eğer kesinti varsa vergi tablosuna eksi olarak yansıt
                if (kesinti > 0) {
                    ekle_veya_guncelle_tevkifat(frm, kesinti, doc.aciklama);
                }
            });
    }
});

// Vergi Tablosuna Eksi Satır Ekleyen Fonksiyon
function ekle_veya_guncelle_tevkifat(frm, kesinti_tutari, aciklama) {
    // DİKKAT: BURASI ÇOK ÖNEMLİ!
    // Hesap Planındaki tevkifat hesabının TAM ADINI buraya yazmalısın.
    // Örnek: "360.01 - Ödenecek Tevkifatlar - GÜLSOFT"
    let muhasebe_hesabi = "HESAP ADINI BURAYA YAZIN"; 

    let tevkifat_row = null;
    if (frm.doc.taxes) {
        tevkifat_row = frm.doc.taxes.find(t => t.description && t.description.includes("Tevkifat Kesintisi"));
    }

    // Eğer tabloda tevkifat satırı yoksa yeni ekle
    if (!tevkifat_row) {
        tevkifat_row = frm.add_child("taxes");
        tevkifat_row.charge_type = "Actual"; // Gerçekleşen tutar
        tevkifat_row.account_head = muhasebe_hesabi;
    }
    
    // Değerleri güncelle (Tutar EKSİ olmalı ki faturadan düşsün)
    tevkifat_row.description = "Tevkifat Kesintisi (" + aciklama + ")";
    tevkifat_row.tax_amount = -kesinti_tutari;
    
    // Tabloyu yenile ki ERPNext genel toplamı yeniden hesaplasın
    frm.refresh_field("taxes");
}

// Tevkifat kodu silinirse tablodaki eksi satırı da kaldıran fonksiyon
function temizle_tevkifat_satiri(frm) {
    if (frm.doc.taxes) {
        let baslangic = frm.doc.taxes.length;
        frm.doc.taxes = frm.doc.taxes.filter(t => !(t.description && t.description.includes("Tevkifat Kesintisi")));
        if (frm.doc.taxes.length < baslangic) {
            frm.refresh_field("taxes");
        }
    }
}
